import { test, expect } from '@playwright/test';

test('create item via API, verify in UI', async ({ page, request }) => {
  // Create data via API
  const response = await request.post('/api/items', {
    data: { title: 'E2E Test Item', status: 'active' },
  });
  const item = await response.json();

  // Verify in browser
  await page.goto('/items');
  await expect(page.getByText('E2E Test Item')).toBeVisible();

  // Cleanup via API
  await request.delete('/api/items/' + item.id);
});
EOF

fullScript:
#!/bin/bash
# Playwright API Testing Setup
set -euo pipefail

echo "=== Setting Up API Tests ==="

mkdir -p tests

cat > tests/api.spec.ts << 'APITEST'
import { test, expect } from '@playwright/test';

test.describe('API Health & CRUD', () => {
  test('health check', async ({ request }) => {
    const response = await request.get('/api/health');
    expect(response.ok()).toBeTruthy();
    const data = await response.json();
    expect(data.status).toBe('healthy');
  });

  test('CRUD workflow', async ({ request }) => {
    // Create
    const createRes = await request.post('/api/items', {
      data: { title: 'Test Item', description: 'Created by Playwright' },
    });
    expect(createRes.status()).toBe(201);
    const created = await createRes.json();
    const id = created.id;

    // Read
    const getRes = await request.get(`/api/items/${id}`);
    expect(getRes.ok()).toBeTruthy();

    // Update
    const updateRes = await request.put(`/api/items/${id}`, {
      data: { title: 'Updated Item' },
    });
    expect(updateRes.ok()).toBeTruthy();

    // Delete
    const deleteRes = await request.delete(`/api/items/${id}`);
    expect(deleteRes.ok()).toBeTruthy();
  });
});
APITEST

echo "Created tests/api.spec.ts"
echo ""
echo "=== Run API Tests ==="
echo "npx playwright test tests/api.spec.ts"
